def gen(rng, size):
    n = rng.randint(3, 12)
    pool = list(range(1, 101))
    rng.shuffle(pool)
    nums = pool[:n]
    if rng.random() < 0.5:
        mask = rng.randint(1, (1 << n) - 2)
        prod = 1
        for i in range(n):
            if mask & (1 << i):
                prod *= nums[i]
        target = prod
    else:
        target = rng.randint(1, 10**6)
    return [nums, target]

