class Solution:
    def checkEqualPartitions(self, nums, target):
        n = len(nums)
        for mask in range(1, (1 << n) - 1):
            p1 = 1
            p2 = 1
            for i in range(n):
                if mask & (1 << i):
                    p1 *= nums[i]
                else:
                    p2 *= nums[i]
            if p1 == target and p2 == target:
                return True
        return False

