var checkEqualPartitions = function(nums, target) {
    const n = nums.length;
    const tgt = BigInt(target);
    let total = 1n;
    for (const v of nums) total *= BigInt(v);
    if (total !== tgt * tgt) return false;
    for (let mask = 1; mask < (1 << n) - 1; mask++) {
        let p = 1n;
        for (let i = 0; i < n; i++) {
            if (mask & (1 << i)) {
                p *= BigInt(nums[i]);
                if (p > tgt) break;
            }
        }
        if (p === tgt) return true;
    }
    return false;
};
